-- 1. ADVERTENCIA: Este comando borrará TODOS los personajes actuales de tu servidor y los inventarios de los usuarios.
-- Ejecútalo con cuidado.

DELETE FROM public.collectibles;

-- 2. Insertando nueva colección de personajes anime:

ON CONFLICT (id) DO UPDATE SET 
  series = EXCLUDED.series, 
  name = EXCLUDED.name,
  description = EXCLUDED.description,
  rarity = EXCLUDED.rarity,
  image_url = EXCLUDED.image_url;
